/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    .hover-lift { transition: transform 0.3s var(--ease), box-shadow 0.3s var(--ease), border-color 0.3s; }
    .hover-lift:hover { transform: translateY(-6px); box-shadow: var(--sh-md); border-color: rgba(51,133,255,0.15); }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* STATS STRIP                                                                */
    /* ========================================================================== */
    .stats-section { margin-top: -50px; position: relative; z-index: 10; padding-bottom: 40px; }
    .stat-box {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-md); 
      padding: 24px 20px; text-align: center; box-shadow: var(--sh-sm);
    }
    .stat-num { font-family: 'Syne', sans-serif; font-size: 1.8rem; font-weight: 800; color: var(--primary); line-height: 1; }
    .stat-lbl { font-size: .7rem; font-weight: 800; color: var(--text-m); margin-top: 8px; text-transform: uppercase; letter-spacing: .05em; }

    /* ========================================================================== */
    /* FEATURED TOPPER (Glassmorphism)                                             */
    /* ========================================================================== */
    .featured-topper-box {
      background: linear-gradient(135deg, var(--digital-blue-900) 0%, var(--digital-blue-800) 100%);
      border-radius: var(--r-xl); padding: 50px; position: relative; overflow: hidden;
      display: flex; align-items: center; gap: 40px; color: #fff; box-shadow: var(--sh-lg);
      margin-bottom: 60px;
    }
    .featured-topper-box::before {
      content: ''; position: absolute; top: -50%; right: -20%; width: 500px; height: 500px;
      background: radial-gradient(circle, rgba(51, 133, 255, 0.2) 0%, transparent 70%);
    }
    .ft-badge {
      display: inline-block; background: var(--gold); color: #000; font-weight: 900; 
      font-size: .75rem; text-transform: uppercase; padding: 6px 16px; border-radius: 50px;
      margin-bottom: 16px; letter-spacing: .05em;
    }
    .ft-avatar {
      width: 160px; height: 160px; border-radius: 50%; border: 6px solid rgba(255,255,255,0.1);
      box-shadow: 0 12px 30px rgba(0,0,0,0.3); object-fit: cover; flex-shrink: 0;
    }
    .ft-content h2 { font-family: 'Syne', sans-serif; font-size: 2.2rem; font-weight: 800; margin-bottom: 8px; }
    .ft-info { display: flex; gap: 24px; margin-top: 24px; }
    .ft-stat { display: flex; flex-direction: column; }
    .ft-stat-val { font-family: 'Syne', sans-serif; font-size: 1.5rem; font-weight: 800; color: var(--gold); }
    .ft-stat-lbl { font-size: .75rem; color: rgba(255,255,255,0.6); text-transform: uppercase; font-weight: 700; margin-top: 4px; }

    /* ========================================================================== */
    /* TOPPER GRID & CARDS                                                        */
    /* ========================================================================== */
    .topper-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(340px, 1fr));
      gap: 24px;
      margin-top: 40px;
    }
    .topper-card {
      background: #fff; border: 1px solid var(--bdr); border-radius: var(--r-xl);
      padding: 32px; height: 100%; box-shadow: var(--sh-sm);
      display: flex; flex-direction: column; transition: all var(--t);
      cursor: pointer;
    }
    .topper-card:hover { transform: translateY(-8px); box-shadow: var(--sh-md); border-color: var(--primary-l); }

    .topper-card-header { display: flex; align-items: center; gap: 16px; margin-bottom: 24px; }
    .tc-icon { 
      width: 52px; height: 52px; border-radius: 14px; background: var(--primary-xl);
      color: var(--primary); display: flex; align-items: center; justify-content: center;
      font-size: 1.8rem;
    }
    .topper-card h3 { font-size: 1.25rem; font-weight: 800; color: var(--primary-d); margin: 0; font-family: 'Syne', sans-serif;}

    .rank-preview-list { list-style: none; padding: 0; margin: 0 0 20px 0; }
    .rank-row { 
      display: flex; align-items: center; justify-content: space-between; 
      padding: 10px 0; border-bottom: 1px solid var(--bdr-s); 
    }
    .rank-row:last-child { border-bottom: none; }
    .rank-name { font-size: .92rem; font-weight: 700; color: var(--text-s); display: flex; align-items: center; gap: 8px; }
    .rank-medal { font-size: 1.2rem; }
    .rank-pct { font-family: 'Syne', sans-serif; font-weight: 800; font-size: .85rem; color: var(--primary); }

    .view-action {
      margin-top: auto; font-size: 0.85rem; color: var(--text-m); font-weight: 700;
      display: flex; align-items: center; gap: 6px; border-top: 1px solid var(--bdr-s); padding-top: 18px;
    }
    .topper-card:hover .view-action { color: var(--primary); }

    /* ========================================================================== */
    /* HALL OF FAME - ARCHIVE                                                     */
    /* ========================================================================== */
    .archive-section { background: #fff; border-top: 1px solid var(--bdr-s); padding: 80px 0; }
    .hof-row {
      display: flex; align-items: center; gap: 30px; padding: 24px;
      border-radius: var(--r-lg); border: 1px solid var(--bdr-s); margin-bottom: 16px;
      transition: all var(--t);
    }
    .hof-row:hover { background: var(--sur-2); border-color: var(--primary-l); transform: translateX(10px); }
    .hof-year { font-family: 'Syne', sans-serif; font-weight: 800; font-size: 1.5rem; color: var(--primary-d); width: 100px; }
    .hof-topper { display: flex; align-items: center; gap: 12px; flex-grow: 1; }
    .hof-topper strong { font-size: 1.05rem; color: var(--text); }
    .hof-dept { font-size: .85rem; color: var(--text-m); text-transform: uppercase; font-weight: 700; letter-spacing: .05em; }
    .hof-medal { font-size: 1.5rem; }

    /* ========================================================================== */
    /* SPLIT-LAYOUT MODAL                                                         */
    /* ========================================================================== */
    .modal-overlay {
      display: none;
      position: fixed; inset: 0;
      background: rgba(0,14,36,0.65);
      z-index: 10000;
      align-items: center; justify-content: center;
      padding: 20px;
      backdrop-filter: blur(6px);
    }
    .modal-overlay.open { display: flex; }

    .modal-box {
      width: 860px; max-width: 100%;
      background: #fff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex;
      flex-direction: row;
      position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .m-left {
      width: 40%;
      position: relative;
      display: flex; align-items: center; justify-content: center;
      background: linear-gradient(135deg, var(--digital-blue-100), var(--digital-blue-50));
      border-right: 1px solid var(--bdr-s);
      padding: 40px; font-size: 7rem;
    }
    .m-right { 
      width: 60%;
      padding: 48px 40px; 
      background: #fff; 
      overflow-y: auto;
      max-height: 85vh;
      position: relative;
    }

    .m-close {
      position: absolute; top: 20px; right: 20px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur-2); color: var(--text-s); 
      border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      cursor: pointer; font-size: 1.1rem; z-index: 10;
      transition: all 0.2s;
    }
    .m-close:hover { background: var(--error); color: #fff; border-color: var(--error); transform: rotate(90deg); }

    .m-dept-title {
      font-size: 1.8rem; font-weight: 800; color: var(--primary-d);
      margin: 0 0 6px 0; line-height: 1.2; font-family: 'Syne', sans-serif;
    }
    .m-sub { font-size: .9rem; font-weight: 700; color: var(--text-m); text-transform: uppercase; letter-spacing: .05em; margin-bottom: 32px; display: block;}

    .m-topper-list { list-style: none; padding: 0; margin: 0; }
    .m-topper-item {
      display: flex; align-items: center; gap: 20px;
      padding: 16px 0; border-bottom: 1px solid var(--bdr-s);
    }
    .m-topper-item:last-child { border-bottom: none; }

    .rank-circle {
      width: 44px; height: 44px; border-radius: 50%;
      display: flex; align-items: center; justify-content: center;
      font-family: 'Syne', sans-serif; font-weight: 800; font-size: 1.1rem; flex-shrink: 0;
      box-shadow: var(--sh-xs);
    }
    .rc-1 { background: var(--gold); color: #fff; }
    .rc-2 { background: var(--silver); color: #fff; }
    .rc-3 { background: var(--bronze); color: #fff; }
    .rc-other { background: var(--digital-blue-50); color: var(--primary); }

    .m-info { flex-grow: 1; }
    .m-name { font-size: 1.05rem; font-weight: 700; color: var(--primary-d); margin-bottom: 6px; }

    .m-pct-bar-wrap { display: flex; align-items: center; gap: 12px; }
    .m-pct-bar { height: 6px; flex-grow: 1; background: var(--sur-3); border-radius: 10px; overflow: hidden; }
    .m-pct-fill { height: 100%; background: var(--primary); border-radius: 10px; transition: width 1s var(--ease); width: 0; }
    .m-pct-val { font-family: 'Syne', sans-serif; font-weight: 800; font-size: .85rem; color: var(--primary); min-width: 45px; }

    @media (max-width: 768px) {
      .featured-topper-box { flex-direction: column; text-align: center; padding: 40px 24px; }
      .ft-info { justify-content: center; }
      .modal-box { flex-direction: column; width: 92%; }
      .m-left { width: 100%; min-height: 180px; padding: 30px; border-right: none; border-bottom: 1px solid var(--bdr-s); font-size: 4rem; }
      .m-right { width: 100%; padding: 32px 24px; }
      .m-dept-title { font-size: 1.5rem; }
      .hof-row { flex-direction: column; text-align: center; gap: 10px; }
      .hof-year { width: auto; font-size: 1.2rem; }
    }

    /* ========================================================================== */
    /* ANIMATIONS                                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }

    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }
    .delay-3 { transition-delay: .15s; }
    .delay-4 { transition-delay: .2s; }

